<template>
  <div class="chart mb-4">
    <Line :data="data" :options="options" />
  </div>
</template>

<script setup lang="ts">
import { GetSensorChartDataResponse } from '@/resource/sensor';
import {
  CategoryScale,
  Chart as ChartJS,
        Legend, LegendElement,
        LineElement, LegendItem,
  LinearScale,
  PointElement,
  Title,
  Tooltip,
} from 'chart.js';
import { computed, onMounted } from 'vue'; 
import { Line } from 'vue-chartjs';

interface Props {
    chartData: GetSensorChartDataResponse;
}

const props = defineProps<Props>();

ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
    Legend,
);

    const data = computed<any>(() => {
        //const title = props.chartData.chartTitle.split('_')[1].trim().normalize('NFKC');
        //let a = props.chartData.chartTitle;
        //const regex = /��/u;
        //alert(props.chartData.chartTitle + regex.test(title)) ;
        //(props.chartData?.lstData || []).filter((dataSet) => dataSet.label.includes('ĵ��')).every((dataset) => alert(dataset.label));
            return {
                type: 'line',
                datasets:
                    (props.chartData?.lstData || [])
                        .map((dataset, index) => {
                            // �� alert �Ӱ���
                             //alert('Dataset label length: ' + dataset.label.length);
                            if (dataset.label.toString().trim().includes("��l��")) {
                                alert('Dataset label: ' + dataset.label);
                            }
                            if (dataset.label === "��l��") {
                                alert('Exact match found: ' + dataset.label);
                            }
                            for (let i = 0; i < dataset.label.length; i++) {
                               // alert(`Character ${i}: ${dataset.label.charAt(i)} (code: ${dataset.label.charCodeAt(i)})`);
                            }
                            //alert(dataset.label.charCodeAt(1));
                            //if (dataset.label.charCodeAt(1) == 22987) alert("good");// 20540
                return{
                    ...dataset,
                    //label: props.chartData.chartTitle.replace("()", ""),
                    data: dataset.data.map((point) => ({
                        ...point,
                        x: formatDate(new Date(point.x)),
                    })),
                    borderWidth: 1,
                    pointRadius: 0, // ������ƺ��I�����
                    ...props.chartData.sensorId.includes("EQ") ? { borderColor: getBorderColor(index) } : {}, // �ʺA�]�w�u�q�C��
                    ...props.chartData.sensorId.includes("EQ") ? { backgroundColor: getBorderColor(index) } : {}, // �ʺA�]�w�I���C��
                    ...dataset.label.charCodeAt(1) == 22987 ? { borderColor: 'rgb(160,160,160)' } : {},
                    ...dataset.label.charCodeAt(1) == 22987 ? { backgroundColor: 'rgb(160,160,160)' } : {},
                }}) ?? [],
            };  
});
    function getBorderColor(index: number): string {
        const colors = ['rgb(192, 0, 0)', 'rgb(192, 192, 0)', 'rgb(0, 192, 0)'];
        return colors[index % colors.length]; // �ھگ��޿���C��
    }
const options = computed(() => {
  return {
    responsive: true,
    maintainAspectRatio: false,
  };
});
    const formatDate = (date: Date): string => {
        let add =0;// 8 * 60 * 60 * 1000;
        
    // �ƻs��l�������A�קK�����ק��l���
    const adjustedDate = new Date(date.getTime() + add);

    const year = String(adjustedDate.getFullYear()).slice(-4);
    const month = String(adjustedDate.getMonth() + 1).padStart(2, '0');
    const day = String(adjustedDate.getDate()).padStart(2, '0');
    const hours = String(adjustedDate.getHours()).padStart(2, '0');
    const minutes = String(adjustedDate.getMinutes()).padStart(2, '0');
  return `${year}-${month}-${day} ${hours}:${minutes}`;
};
</script>

